    "chat_auto_send": "ಸ್ವಯಂ-ಕಳುಹಿಸುವ ಮೋಡ್: ನೀವು ಮಾತನಾಡುವುದನ್ನು ಅಥವಾ ಟೈಪ್ ಮಾಡುವುದನ್ನು ಮುಗಿಸಿದ ನಂತರ ಸಂದೇಶಗಳನ್ನು ಸ್ವಯಂಚಾಲಿತವಾಗಿ ಕಳುಹಿಸಲಾಗುತ್ತದೆ.",
    "chat_show_me": "Show Me ಮೋಡ್: ಪರದೆಯ ಮೇಲೆ ಅಂಶಗಳನ್ನು ಹೈಲೈಟ್ ಮಾಡುವ ಮೂಲಕ ವೈಶಿಷ್ಟ್ಯಗಳನ್ನು ಪ್ರದರ್ಶಿಸಲು AlloBot ಅನ್ನು ಕೇಳಿ.",
    "chat_save_advice_btn": "AlloBot ನ ಸಲಹೆ ಮತ್ತು ಸೂಚನೆಗಳನ್ನು ನಂತರದ ಉಲ್ಲೇಖಕ್ಕಾಗಿ ನಿಮ್ಮ ಸುಳಿವುಗಳ ಸಂಗ್ರಹಕ್ಕೆ ಉಳಿಸಿ.",
    "glossary_search": "ನಿಮ್ಮ ಪದಕೋಶದಲ್ಲಿ ನಿರ್ದಿಷ್ಟ ಪದಗಳನ್ನು ಹುಡುಕಿ. ಪಟ್ಟಿಯನ್ನು ಫಿಲ್ಟರ್ ಮಾಡಲು ಒಂದು ಪದವನ್ನು ಟೈಪ್ ಮಾಡಿ.",
    "glossary_add_term": "ಪದಕೋಶಕ್ಕೆ ಗ್ರಾಹ್ಯ ಪದವನ್ನು ಸೇರಿಸಿ. ಪದ ಮತ್ತು ಐಚ್ಛಿಕವಾಗಿ ವ್ಯಾಖ್ಯಾನವನ್ನು ಸೇರಿಸಿ.",
    "glossary_edit": "ವ್ಯಾಖ್ಯಾನ, ಶ್ರೇಣಿ, ಚಿತ್ರಗಳು ಮತ್ತು ಭಾಷಾಂತರಗಳು ಸೇರಿದಂತೆ ಈ ಪದಕೋಶ ಪದವನ್ನು ಸಂಪಾದಿಸಿ.",
    "glossary_speak_term": "ಈ ಪದವನ್ನು ಗಟ್ಟಿಯಾಗಿ ಉಚ್ಚರಿಸಿದಂತೆ ಕೇಳಿ. ಸರಿಯಾದ ಉಚ್ಚಾರಣೆಯನ್ನು ಕಲಿಯಲು ಸಹಾಯಕ.",
    "glossary_standard_flashcards": "ಮುಂಭಾಗದಲ್ಲಿ ಪದ ಮತ್ತು ಹಿಂಭಾಗದಲ್ಲಿ ವ್ಯಾಖ್ಯಾನದೊಂದಿಗೆ ಸಾಂಪ್ರದಾಯಿಕ ಫ್ಲ್ಯಾಶ್‌ಕಾರ್ಡ್‌ಗಳನ್ನು ರಚಿಸಿ.",
    "glossary_language_flashcards": "ಆಯ್ದ ಭಾಷೆಯಲ್ಲಿ ಭಾಷಾಂತರಗಳೊಂದಿಗೆ ದ್ವಿಭಾಷಾ ಫ್ಲ್ಯಾಶ್‌ಕಾರ್ಡ್‌ಗಳನ್ನು ರಚಿಸಿ.",
    "glossary_export_standard": "ಪದಕೋಶವನ್ನು ಮುದ್ರಿಸಬಹುದಾದ ಫ್ಲ್ಯಾಶ್‌ಕಾರ್ಡ್ PDF ಅಥವಾ ಚಿತ್ರ ಫೈಲ್‌ಗಳಾಗಿ ರಫ್ತು ಮಾಡಿ.",
    "glossary_export_language": "ಭಾಷಾ ಕಲಿಯುವವರಿಗಾಗಿ ಭಾಷಾಂತರಗಳೊಂದಿಗೆ ದ್ವಿಭಾಷಾ ಪದಕೋಶವನ್ನು ರಫ್ತು ಮಾಡಿ.",
    "glossary_memory_game": "ಶಬ್ದಕೋಶವನ್ನು ಅಭ್ಯಾಸ ಮಾಡಲು ಮೆಮೊರಿ ಹೊಂದಾಣಿಕೆ ಆಟವನ್ನು ಆಡಿ. ಪದಗಳನ್ನು ವ್ಯಾಖ್ಯಾನಗಳೊಂದಿಗೆ ಹೊಂದಿಸಿ.",
    "glossary_crossword": "ನಿಮ್ಮ ಪದಕೋಶದಿಂದ ಪದಬಂಧ ಒಗಟನ್ನು ರಚಿಸಿ. ವ್ಯಾಖ್ಯಾನಗಳು ಸುಳಿವುಗಳಾಗಿ, ಪದಗಳು ಉತ್ತರಗಳಾಗಿ.",
    "glossary_matching": "ಹೊಂದಾಣಿಕೆ ಚಟುವಟಿಕೆಯನ್ನು ರಚಿಸಿ. ಪದಗಳನ್ನು ಅವುಗಳ ವ್ಯಾಖ್ಯಾನಗಳೊಂದಿಗೆ ಸಂಪರ್ಕಿಸಲು ಗೆರೆಗಳನ್ನು ಎಳೆಯಿರಿ.",
    "glossary_word_search": "ನಿಮ್ಮ ಪದಕೋಶ ಪದಗಳನ್ನು ಒಳಗೊಂಡ ಪದ ಹುಡುಕಾಟ ಒಗಟನ್ನು ರಚಿಸಿ. ಮೋಜಿನ ಶಬ್ದಕೋಶ ಅಭ್ಯಾಸ!",
    "glossary_scramble": "ಪದ ಗೊಂದಲ ಚಟುವಟಿಕೆಯನ್ನು ರಚಿಸಿ. ಶಬ್ದಕೋಶ ಪದಗಳನ್ನು ಉಚ್ಚರಿಸಲು ಅಕ್ಷರಗಳನ್ನು ಸರಿಪಡಿಸಿ.",
    "simplified_grade_level": "ಪಠ್ಯದ ಓದುವ ಮಟ್ಟವನ್ನು ಸರಿಹೊಂದಿಸಿ. ಕಡಿಮೆ ತರಗತಿಗಳು = ಸರಳ ಶಬ್ದಕೋಶ ಮತ್ತು ಚಿಕ್ಕ ವಾಕ್ಯಗಳು.",
    "simplified_language": "ಬಹುಭಾಷಾ ತರಗತಿಗಳಿಗಾಗಿ ಸರಳೀಕೃತ ಪಠ್ಯವನ್ನು ಮತ್ತೊಂದು ಭಾಷೆಗೆ ಭಾಷಾಂತರಿಸಿ.",
    "simplified_read_mode": "ಓದು ಮೋಡ್ ಅನ್ನು ಸಕ್ರಿಯಗೊಳಿಸಿ: ಪದ-ಪದ ಹೈಲೈಟ್ ಮಾಡುವಿಕೆಯೊಂದಿಗೆ ಗಟ್ಟಿಯಾಗಿ ಓದುವ ಪಠ್ಯವನ್ನು ಆಲಿಸಿ.",
    "simplified_define_mode": "ವ್ಯಾಖ್ಯಾನ ಮೋಡ್ ಅನ್ನು ಸಕ್ರಿಯಗೊಳಿಸಿ: ಯಾವುದೇ ಪದದ ವ್ಯಾಖ್ಯಾನವನ್ನು ನೋಡಲು ಮತ್ತು ಉಚ್ಚಾರಣೆಯನ್ನು ಕೇಳಲು ಅದರ ಮೇಲೆ ಕ್ಲಿಕ್ ಮಾಡಿ.",
