    "bingo_speed_slider": "ಸ್ವಯಂ-ಪ್ಲೇ ಮೋಡ್‌ನಲ್ಲಿ ಪದಗಳನ್ನು ಎಷ್ಟು ವೇಗವಾಗಿ ಕರೆಯಲಾಗುತ್ತದೆ ಎಂಬುದನ್ನು ಸರಿಹೊಂದಿಸಿ.",
    "bingo_toggle_autoplay": "ಸ್ವಯಂಚಾಲಿತ ಕರೆಯುವಿಕೆಯನ್ನು ಟಾಗಲ್ ಮಾಡಿ. ಸಕ್ರಿಯಗೊಳಿಸಿದಾಗ, ಪದಗಳನ್ನು ನಿಯಮಿತ ಮಧ್ಯಂತರಗಳಲ್ಲಿ ಕರೆಯಲಾಗುತ್ತದೆ.",
    "bingo_toggle_history": "ಆಟದ ಸಮಯದಲ್ಲಿ ಉಲ್ಲೇಖಕ್ಕಾಗಿ ಕರೆದ ಪದಗಳ ಇತಿಹಾಸವನ್ನು ತೋರಿಸಿ ಅಥವಾ ಮರೆಮಾಡಿ.",
    "bingo_close_btn": "Bingo ಆಟವನ್ನು ಮುಚ್ಚಿ ಮತ್ತು ಪದಕೋಶಕ್ಕೆ ಹಿಂತಿರುಗಿ.",
    "glossary_play_bingo": "ನಿಮ್ಮ ಪದಕೋಶ ಪದಗಳನ್ನು ಬಳಸಿ Bingo ಆಟವನ್ನು ಪ್ರಾರಂಭಿಸಿ! ಇಡೀ ತರಗತಿ ಶಬ್ದಕೋಶ ಪರಿಶೀಲನೆಗೆ ಉತ್ತಮ.",
    "crossword_game_container": "ನಿಮ್ಮ ಪದಕೋಶದಿಂದ ರಚಿಸಲಾದ ಸಂವಾದಾತ್ಮಕ ಪದಬಂಧ ಒಗಟು. ಟೈಪ್ ಮಾಡಲು ಪ್ರಾರಂಭಿಸಲು ಒಂದು ಸೆಲ್ ಮೇಲೆ ಕ್ಲಿಕ್ ಮಾಡಿ.",
