    "brainstorm_card": "ಬ್ರೈನ್‌ಸ್ಟಾರ್ಮ್ ಆಲೋಚನೆ ಕಾರ್ಡ್. ವಿವರಗಳು ಮತ್ತು ಮುಂದುವರಿಕೆಗಳಿಗಾಗಿ ವಿಸ್ತರಿಸಲು ಕ್ಲಿಕ್ ಮಾಡಿ.",
    "brainstorm_guide": "ಪರಿಣಾಮಕಾರಿ ಬ್ರೈನ್‌ಸ್ಟಾರ್ಮಿಂಗ್ ಅಧಿವೇಶನಗಳಿಗಾಗಿ ಸಲಹೆಗಳು ಮತ್ತು ತಂತ್ರಗಳು.",
    "brainstorm_simulation_type": "ಬ್ರೈನ್‌ಸ್ಟಾರ್ಮ್ ಸ್ವರೂಪ ಆಯ್ಕೆಮಾಡಿ: ಮೈಂಡ್ ಮ್ಯಾಪ್, ಚರ್ಚಾ ಪ್ರಶ್ನೆಗಳು, ಅಥವಾ What-If ಸನ್ನಿವೇಶಗಳು.",
    "brainstorm_step_count": "ರಚಿಸಬೇಕಾದ ಬ್ರೈನ್‌ಸ್ಟಾರ್ಮಿಂಗ್ ಪ್ರಾಂಪ್ಟ್‌ಗಳು ಅಥವಾ ಹಂತಗಳ ಸಂಖ್ಯೆ.",
